# Task Complete: YouTube Pipeline

## scripts/youtube_ingest.js
```javascript
#!/usr/bin/env node
const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

// Parse command line arguments
const args = process.argv.slice(2);
let url = null;
let tags = [];

for (let i = 0; i < args.length; i++) {
  if (args[i] === '--url') {
    url = args[i + 1];
  } else if (args[i] === '--tags') {
    tags = args[i + 1].split(',');
  }
}

if (!url) {
  console.error('Error: --url is required');
  process.exit(1);
}

// Extract video ID from URL
function extractVideoId(url) {
  const regex = /(?:youtu\.be\/|youtube\.com\/(?:embed\/|v\/|watch\?v=|watch\?.+&v=))((\w|-){11})/;
  const match = url.match(regex);
  return match ? match[1] : null;
}

const videoId = extractVideoId(url);
if (!videoId) {
  console.error('Error: Invalid YouTube URL format');
  process.exit(1);
}

// Step 1: Extract transcript via yt-dlp
try {
  execSync(`yt-dlp --write-auto-sub --sub-lang en --skip-download --output "${videoId}" "${url}"`, { 
    stdio: 'inherit' 
  });
} catch (e) {
  console.error('yt-dlp failed. Ensure yt-dlp is installed and in PATH.');
  process.exit(1);
}

// Find transcript file
const transcriptFile = [`${videoId}.en.vtt`, `${videoId}.en.ttml`]
  .find(file => fs.existsSync(file));

if (!transcriptFile) {
  console.error(`No transcript found for video ID ${videoId}. Check yt-dlp output.`);
  process.exit(1);
}

// Step 2: Clean transcript
let transcript = fs.readFileSync(transcriptFile, 'utf-8');
const lines = transcript.split('\n');
const cleanedLines = lines.filter(line => {
  // Skip timecodes (format: 00:00:00.000 --> 00:00:01.000)
  if (/^\d{2}:\d{2}:\d{2}\.\d{3} --> \d{2}:\d{2}:\d{2}\.\d{3}$/.test(line)) {
    return false;
  }
  return line.trim() !== '';
});

transcript = cleanedLines.join(' ');
if (transcript.length > 8000) {
  transcript = transcript.substring(0, 8000);
}

console.log(`📺 YouTube Pipeline`);
console.log(`   URL: ${url}`);
console.log(`   ✅ Transcript extracted (${transcript.length} words)`);

// Step 3: Summarize with qwen3
const prompt = `You are a knowledge extraction agent. Summarize this YouTube video transcript into structured intelligence.

Transcript:
${transcript}

Output JSON with this exact structure:
{
  "title": "inferred video title",
  "summary": "2-3 sentence overview",
  "key_points": ["point 1", "point 2", ...],
  "action_items": ["what to build or try", ...],
  "ares_relevance": "how this applies to ARES or Ashish's projects (1-2 sentences)",
  "tags": ["tag1", "tag2"],
  "source_url": "${url}"
}`;

const ollamaUrl = 'http://localhost:11434/api/generate';
const payload = {
  model: 'qwen3:30b-a3b',
  prompt: prompt,
  format: 'json',
  stream: false,
  options: { temperature: 0.1 }
};

try {
  console.log(`   🤖 Summarizing with qwen3...`);
  const response = await fetch(ollamaUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload)
  });

  if (!response.ok) {
    throw new Error(`Ollama API error: ${response.statusText}`);
  }

  const data = await response.json();
  const summaryJson = JSON.parse(data.response);

  // Step 4: Save to Firestore
  const { db } = require('./firestore-client');
  const docRef = db.collection('knowledge_base').doc();
  await docRef.set({
    type: 'youtube',
    url,
    title: summaryJson.title,
    summary: summaryJson.summary,
    key_points: summaryJson.key_points,
    action_items: summaryJson.action_items,
    ares_relevance: summaryJson.ares_relevance,
    tags: [...tags, 'youtube'],
    ingestedAt: new Date().toISOString(),
    wordCount: transcript.length / 5
  });

  console.log(`   📝 Firestore: knowledge_base/${docRef.id} saved`);

  // Step 5: Save to knowledge directory
  const knowledgeDir = 'knowledge';
  if (!fs.existsSync(knowledgeDir)) {
    fs.mkdirSync(knowledgeDir);
  }

  const date = new Date().toISOString().split('T')[0];
  const fileName = `youtube_${videoId}_${date}.md`;
  const filePath = path.join(knowledgeDir, fileName);

  const markdownContent = `# ${summaryJson.title}

**Source:** ${url}
**Date:** ${date}
**Tags:** ${tags.join(', ')}

## Summary
${summaryJson.summary}

## Key Points
${summaryJson.key_points.map(point => `- ${point}`).join('\n')}

## Action Items
${summaryJson.action_items.map(item => `- ${item}`).join('\n')}

## ARES Relevance
${summaryJson.ares_relevance}`;

  fs.writeFileSync(filePath, markdownContent);
  console.log(`   📁 knowledge/${fileName} saved`);

  // Clean up transcript file
  fs.unlinkSync(transcriptFile);
  console.log(`   🎉 Done`);

} catch (error) {
  console.error('Summary generation failed:', error.message);
  process.exit(1);
}
```

